      50% {
        box-shadow: 0 0 40px rgba(255, 204, 0, .6)
      }
    }

    .pulse-glow {
      animation: pulse-glow 2s ease-in-out infinite
    }

    .progress-bar {
      display: flex;
      gap: 4px;
