      border-radius: 6px;
      box-shadow: inset 0 -2px 0 rgba(0, 0, 0, .15);
      transition: all .3s;
      position: relative
    }

    .progress-brick.filled::after {
      content: '';
      position: absolute;
      top: 2px;
      left: 50%;
      transform: translateX(-50%);
      width: 12px;
      height: 12px;
      border-radius: 50%;
