      font-size: 16px;
      color: var(--fg);
      resize: none;
      outline: none box-shadow: inset 0 -3px 0 rgba(0, 0, 0, 0.1);
    }

    textarea:focus {
      border-color: var(--red)
    }

    @keyframes lego-bounce {

      0%,
      100% {
        transform: translateY(0)
      }

      50% {
        transform: translateY(-8px)
      }
    }

    .loading-brick {
      width: 32px;
