  <div class="lego-stripe" style="margin-top:auto"></div>

  <script>
    // Sound
    const clickSound = new Audio('sounds/lego.wav');
    const spinSound = new Audio('sounds/roletta.mp3');
    const winSound = new Audio('sounds/win.mp3');
    const loseSound = new Audio('sounds/lose.mp3');
    const loadingSound = new Audio('sounds/carregamento.mp3');

    function playClick() {
      clickSound.currentTime = 0;
      clickSound.play();
    }

    function playSpinSound() {
      spinSound.currentTime = 0;
      spinSound.loop = false;
      spinSound.play();
    }

    function stopSpinSound() {
      spinSound.pause();
      spinSound.currentTime = 0;
    }

    function playWinSound() {
      winSound.currentTime = 0;
      winSound.play();
    }
    function playLoseSound() {
      loseSound.currentTime = 0;
      loseSound.play();
    }
    function playLoadingSound() {
      loadingSound.currentTime = 0;
      loadingSound.loop = true; // 🔥 fica rodando enquanto carrega
      loadingSound.play();
    }

    function stopLoadingSound() {
      loadingSound.pause();
      loadingSound.currentTime = 0;
    }
    // Navigation
    function goTo(id) {
      playClick();

      window.scrollTo({ top: 0, behavior: 'smooth' });
      document.querySelectorAll('.screen').forEach(function (s) { s.classList.remove('active') });
      document.getElementById(id).classList.add('active');

      if (id === 'quiz') renderQuiz();
      if (id === 'loading') {
        playLoadingSound(); // 🔥 ADICIONADO
        startLoading();
      }
      if (id === 'roulette') buildWheel();
    }

    // Quiz
    var questions = [
      { q: '<i class="fa-solid fa-futbol"></i> Que jogador montarias em versão LEGO?', options: ['Messi 🇦🇷', 'CR7 🇵🇹', 'Vinícius Jr 🇧🇷', 'Mbappé 🇫🇷'] },
      { q: '<i class="fa-solid fa-trophy" style="color:#FFD700"></i> Que seleção merece ganhar o Mundial 2026?', options: ['Brasil 🇧🇷', 'Argentina 🇦🇷', 'França 🇫🇷', 'Portugal 🇵🇹'] },
      { q: '<i class="fa-solid fa-cubes" style="color:#DC2626"></i> Preferes montar ou jogar futebol?', options: ['Montar LEGO! <i class="fa-solid fa-cubes" style="color:#DC2626"></i>', 'Jogar futebol! <i class="fa-solid fa-futbol"></i>', 'Ambos! <i class="fa-solid fa-face-grin-stars" style="color:#F59E0B"></i>', 'Assistir! <i class="fa-solid fa-tv"></i>'] },
      {
        q: '<i class="fa-solid fa-fire" style="color:#DC2626"></i> Se pudesses viver uma cena em LEGO no Mundial, qual seria?',
        options: [
          'Golo no último minuto <i class="fa-solid fa-futbol"></i><i class="fa-solid fa-fire" style="color:#DC2626;margin-left:4px"></i>',
          'Levantar o troféu <i class="fa-solid fa-trophy" style="color:#FFD700"></i>',
          'Defesa impossível do guarda-redes <i class="fa-solid fa-hand" style="color:#2563EB"></i>',
          'Adeptos em festa no estádio <i class="fa-solid fa-star" style="color:#F59E0B"></i>'
        ]
      },
      { q: '<i class="fa-solid fa-earth-americas" style="color:#2563EB"></i> Que cidade-sede do Mundial 2026 gostarias de visitar?', options: ['Nova Iorque <i class="fa-solid fa-landmark" style="color:#DC2626"></i>', 'Los Angeles <i class="fa-solid fa-tree" style="color:#16A34A"></i>', 'Cidade do México 🇲🇽', 'Toronto 🇨🇦'] },
      { q: '<i class="fa-solid fa-brain" style="color:#9333EA"></i> Que set LEGO gostarias mais de ter?', options: ['Estádio LEGO <i class="fa-solid fa-building" style="color:#2563EB"></i>', 'Equipa completa <i class="fa-solid fa-futbol"></i>', 'Troféu FIFA <i class="fa-solid fa-trophy" style="color:#FFD700"></i>', 'Autocarro da Seleção <i class="fa-solid fa-bus" style="color:#F59E0B"></i>'] }
    ];
    var currentQ = 0;
    var brickColors = ['var(--red)', 'var(--blue)', 'var(--yellow)', 'var(--green)', 'var(--orange)', 'var(--red)', 'var(--blue)'];
    var btnColors = ['btn-blue', 'btn-green', 'btn-orange', 'btn-red'];

    function renderQuiz() {
      var q = questions[currentQ];
      document.getElementById('q-counter').textContent = 'Pergunta ' + (currentQ + 1) + ' de ' + questions.length;
      document.getElementById('q-hint').textContent = currentQ < questions.length - 1 ? 'Falta pouco...' : 'Última etapa!';
      document.getElementById('q-micro').innerHTML = currentQ === questions.length - 1 ? '<i class="fa-solid fa-bullseye" style="color:#DC2626"></i> Última pergunta!' : 'Estás a ir bem! <i class="fa-solid fa-fire" style="color:#DC2626"></i>';
      document.getElementById('q-text').innerHTML = q.q;

      var bar = document.getElementById('progress-bar');
      bar.innerHTML = '';
      for (var i = 0; i < questions.length; i++) {
        var b = document.createElement('div');
        b.className = 'progress-brick' + (i < currentQ + 1 ? ' filled' : '');
        b.style.background = i < currentQ + 1 ? brickColors[i % brickColors.length] : 'var(--muted)';
        bar.appendChild(b);
      }

      var opts = document.getElementById('q-options');
      opts.innerHTML = '';
      q.options.forEach(function (opt, i) {
        var b = document.createElement('button');
        b.className = 'btn quiz-option ' + btnColors[i];
        b.innerHTML = opt;
        b.onclick = function () {
          playClick();
          b.classList.add('pressed');
          setTimeout(function () {
            currentQ++;
            if (currentQ < questions.length) renderQuiz();
            else goTo('open');
          }, 300);
        };
        opts.appendChild(b);
      });
    }

    // Loading
    function startLoading() {
      var p = 0;
      var fill = document.getElementById('load-fill');
      var pct = document.getElementById('load-pct');
      var iv = setInterval(function () {
        p += 2.5;
        if (p >= 100) {
          p = 100;
          clearInterval(iv);

          stopLoadingSound(); // 🔥 PARA O SOM

          setTimeout(function () {
            goTo('approval')
          }, 500);
        }
        fill.style.width = p + '%';
        pct.textContent = Math.round(p) + '%';
      }, 100);
    }

    // Roulette
    var prizes = [
      { label: 'TROFÉU LEGO\n', color: 'hsl(4,80%,50%)' },
      { label: '20% DE DESCONTO', color: 'hsl(210,85%,50%)' },
      { label: 'VIAGEM\nLEGO', color: 'hsl(145,65%,42%)' },
      { label: '40% DE DESCONTO', color: 'hsl(48,100%,50%)' },
      { label: 'Vini Jr\nLEGO', color: 'hsl(30,95%,55%)' },
      { label: '60% DE DESCONTO', color: 'hsl(4,80%,50%)' },
      { label: '90% DE DESCONTO', color: 'hsl(145,65%,42%)' },

      // 👇 AGORA É 90%
      { label: 'CR7 LEGO\n', color: 'hsl(210,85%,50%)' },

      { label: 'Messi LEGO\n', color: 'hsl(48,100%,50%)' },
      { label: 'RODA\nNOVAMENTE', color: 'hsl(0,0%,60%)', size: 13 }
    ];

    var rouletteAttempt = 0, spinning = false, wheelRotation = 0;
    var segAngle = 360 / prizes.length;

    function buildWheel() {
      var svg = document.getElementById('wheel');
      svg.innerHTML = '';

      svg.style.filter = "none";

      var defs = document.createElementNS('http://www.w3.org/2000/svg', 'defs');
      svg.appendChild(defs);

      prizes.forEach(function (p, i) {

        var startAngle = i * segAngle;
        var endAngle = (i + 1) * segAngle;

        var s = (startAngle - 90) * Math.PI / 180;
        var e = (endAngle - 90) * Math.PI / 180;

        var R = 130;

        var x1 = 150 + R * Math.cos(s);
        var y1 = 150 + R * Math.sin(s);
        var x2 = 150 + R * Math.cos(e);
        var y2 = 150 + R * Math.sin(e);

        var path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
        path.setAttribute('d', `M150,150 L${x1},${y1} A${R},${R} 0 0,1 ${x2},${y2} Z`);
        path.setAttribute('fill', p.color);
        path.setAttribute('stroke', '#fff');
        path.setAttribute('stroke-width', '3');
        svg.appendChild(path);

        var studs = 5;

        for (var j = 1; j <= studs; j++) {

          var subAngle = startAngle + (segAngle / (studs + 1)) * j;
          var rad = (subAngle - 90) * Math.PI / 180;

          var r = R;

          var sx = 150 + r * Math.cos(rad);
          var sy = 150 + r * Math.sin(rad);

          var stud = document.createElementNS('http://www.w3.org/2000/svg', 'circle');

          stud.setAttribute('cx', sx);
          stud.setAttribute('cy', sy);
          stud.setAttribute('r', '5');
          stud.setAttribute('fill', p.color);
          stud.setAttribute('stroke', 'rgba(0,0,0,0.15)');
          stud.setAttribute('stroke-width', '1');

          svg.appendChild(stud);
        }

        var angle = startAngle + segAngle / 2;

        var textRadius = 75;
        var tx = 150 + textRadius * Math.cos((angle - 90) * Math.PI / 180);
        var ty = 150 + textRadius * Math.sin((angle - 90) * Math.PI / 180);

        var rotation = angle - 90;

        if (angle > 180) {
          rotation += 180;
        }

        var text = document.createElementNS('http://www.w3.org/2000/svg', 'text');

        text.setAttribute('x', tx);
        text.setAttribute('y', ty);
        text.setAttribute('fill', '#fff');
        text.setAttribute('text-anchor', 'middle');
        text.setAttribute('dominant-baseline', 'middle');

        // 👇 AQUI ESTÁ A MÁGICA
        text.setAttribute('font-size', p.size || 12);

        text.setAttribute('font-family', "'VT323', cursive");
        text.setAttribute('transform', `rotate(${rotation}, ${tx}, ${ty})`);

        text.textContent = p.label.replace('\n', ' ');
        svg.appendChild(text);
      });

      var center = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
      center.setAttribute('cx', '150');
      center.setAttribute('cy', '150');
      center.setAttribute('r', '35');
      center.setAttribute('fill', '#e60023');
      center.setAttribute('stroke', '#fff');
      center.setAttribute('stroke-width', '4');
      svg.appendChild(center);

      var clip = document.createElementNS('http://www.w3.org/2000/svg', 'clipPath');
      clip.setAttribute('id', 'logoClip');

      var clipCircle = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
      clipCircle.setAttribute('cx', '150');
      clipCircle.setAttribute('cy', '150');
      clipCircle.setAttribute('r', '25');

      clip.appendChild(clipCircle);
      defs.appendChild(clip);

      var logo = document.createElementNS('http://www.w3.org/2000/svg', 'image');
      logo.setAttribute('href', 'images/logo.png');
      logo.setAttribute('x', '128');
      logo.setAttribute('y', '128');
      logo.setAttribute('width', '44');
      logo.setAttribute('height', '44');
      logo.setAttribute('clip-path', 'url(#logoClip)');

      svg.appendChild(logo);
    }

    function spinWheel() {
      if (spinning) return;

      const svg = document.getElementById('wheel');
      const btn = document.getElementById('spin-btn');

      spinning = true;
      btn.disabled = true;

      playClick();
      playSpinSound(); // 🔥 toca sempre quando a roleta gira

      document.getElementById('roulette-result').innerHTML = '';

      rouletteAttempt++;

      let targetIdx;
      if (rouletteAttempt === 1) {
        targetIdx = 9; // RODE NOVAMENTE
      } else {
        targetIdx = 7; // 90% OFF
      }

      const spins = 6;
      const targetAngle = (targetIdx * segAngle) + (segAngle / 2);
      const ajusteFino = 2;

      wheelRotation += (360 * spins) + (360 - targetAngle) + ajusteFino;

      // animação de rotação
      svg.style.transition = 'transform 4s ease-out';
      svg.style.transform = 'rotate(' + wheelRotation + 'deg)';

      // 🔥 dispara quando a roleta termina a transição
      svg.ontransitionend = function () {
        spinning = false;
        svg.ontransitionend = null; // remove listener

        const rb = document.getElementById('roulette-result');

        if (rouletteAttempt === 1) {
          // Primeiro giro: RODA NOVAMENTE
          rb.innerHTML = '<div class="result-box"><i class="fa-solid fa-face-tired" style="color:#F59E0B"></i> Tenta novamente!</div>';
          document.getElementById('roulette-hint').innerHTML = 'Tens mais uma oportunidade! <i class="fa-solid fa-clover" style="color:#16A34A"></i>';
          playLoseSound(); // som de derrota
          btn.disabled = false;
          btn.innerHTML = 'GIRAR NOVAMENTE! <i class="fa-solid fa-clover" style="color:#16A34A"></i>';
        } else {
          // Segundo giro: vitória
          rb.innerHTML = '<div class="result-box"></div>';
          document.getElementById('win-msg').style.display = '';
          playWinSound();  // 🔥 toca vitória
          fireConfetti();  // 🔥 dispara confetti
          setTimeout(function () {
            goTo('offer');
          }, 4000);
        }
      };
    }
    function fireConfetti() {
      var colors = ['hsl(4,80%,50%)', 'hsl(48,100%,50%)', 'hsl(210,85%,50%)', 'hsl(145,65%,42%)', 'hsl(30,95%,55%)'];
      for (var i = 0; i < 50; i++) {
        var d = document.createElement('div');
        d.className = 'confetti';
        d.style.left = Math.random() * 100 + '%';
        d.style.backgroundColor = colors[Math.floor(Math.random() * colors.length)];
        d.style.animationDelay = Math.random() * 2 + 's';
        d.style.animationDuration = (2 + Math.random() * 2) + 's';
        d.style.width = d.style.height = (8 + Math.random() * 12) + 'px';
        if (Math.random() > .5) d.style.borderRadius = '50%';
        document.body.appendChild(d);
        setTimeout(function (el) { el.remove() }.bind(null, d), 5000);
      }
    }
  </script>
  <script>// TIMER DE 10 MINUTOS EM VERDE
    function startOfferTimer(durationSeconds = 600) {
      const timerEl = document.getElementById('offer-timer');
      let remaining = durationSeconds;

      const interval = setInterval(() => {
        const minutes = Math.floor(remaining / 60);
        const seconds = remaining % 60;
        timerEl.innerHTML = `<i class="fa-solid fa-clock" style="color:#DC2626"></i> Oferta válida por: ${minutes}:${seconds.toString().padStart(2, '0')}`;

        remaining--;

        if (remaining < 0) {
          clearInterval(interval);
          timerEl.innerHTML = '<i class="fa-solid fa-clock" style="color:#DC2626"></i> Tempo esgotado!';
          timerEl.style.color = "var(--red)"; // muda para vermelho quando acabar
          // document.querySelector("#offer button").disabled = true; // opcional
        }
      }, 1000);
    }

    // Inicia o timer ao entrar na tela de oferta
    function goTo(id) {
      playClick();

      window.scrollTo({ top: 0, behavior: 'smooth' });
      document.querySelectorAll('.screen').forEach(function (s) { s.classList.remove('active') });
      document.getElementById(id).classList.add('active');

      if (id === 'quiz') renderQuiz();
      if (id === 'loading') {
        playLoadingSound();
        startLoading();
      }
      if (id === 'roulette') buildWheel();
      if (id === 'offer') startOfferTimer(); // inicia o timer verde
    }</script>


</body></html>